CREATE TABLE saas_product (id VARCHAR(36) PRIMARY KEY,product_key VARCHAR(100) NOT NULL UNIQUE,name VARCHAR(200) NOT NULL,description TEXT,logo_url VARCHAR(1000),active BOOLEAN NOT NULL,created_at TIMESTAMP NOT NULL);
CREATE TABLE saas_plan (id VARCHAR(36) PRIMARY KEY,product_id VARCHAR(36) NOT NULL,plan_key VARCHAR(100) NOT NULL,name VARCHAR(200) NOT NULL,description TEXT,price DECIMAL(19,4) NOT NULL,currency VARCHAR(3) NOT NULL,billing_interval VARCHAR(20) NOT NULL,interval_count INT NOT NULL,trial_days INT NOT NULL,max_activations INT NOT NULL,entitlements_json TEXT,active BOOLEAN NOT NULL,featured BOOLEAN NOT NULL,created_at TIMESTAMP NOT NULL,updated_at TIMESTAMP NOT NULL,CONSTRAINT fk_saas_plan_product FOREIGN KEY(product_id) REFERENCES saas_product(id),CONSTRAINT ux_saas_plan_key UNIQUE(product_id,plan_key));
CREATE TABLE saas_subscription (id VARCHAR(36) PRIMARY KEY,plan_id VARCHAR(36) NOT NULL,customer_id VARCHAR(36),customer_email VARCHAR(190) NOT NULL,status VARCHAR(30) NOT NULL,order_id VARCHAR(36),started_at TIMESTAMP NOT NULL,trial_ends_at TIMESTAMP,current_period_start TIMESTAMP NOT NULL,current_period_end TIMESTAMP,cancel_at_period_end BOOLEAN NOT NULL,cancelled_at TIMESTAMP,created_at TIMESTAMP NOT NULL,CONSTRAINT fk_subscription_plan FOREIGN KEY(plan_id) REFERENCES saas_plan(id));
CREATE TABLE saas_license (id VARCHAR(36) PRIMARY KEY,product_id VARCHAR(36) NOT NULL,plan_id VARCHAR(36) NOT NULL,subscription_id VARCHAR(36),customer_email VARCHAR(190) NOT NULL,order_id VARCHAR(36),key_hash VARCHAR(64) NOT NULL UNIQUE,key_cipher TEXT NOT NULL,key_prefix VARCHAR(20) NOT NULL,status VARCHAR(30) NOT NULL,max_activations INT NOT NULL,issued_at TIMESTAMP NOT NULL,expires_at TIMESTAMP,grace_ends_at TIMESTAMP,last_validated_at TIMESTAMP,created_at TIMESTAMP NOT NULL,CONSTRAINT fk_license_product FOREIGN KEY(product_id) REFERENCES saas_product(id),CONSTRAINT fk_license_plan FOREIGN KEY(plan_id) REFERENCES saas_plan(id),CONSTRAINT fk_license_subscription FOREIGN KEY(subscription_id) REFERENCES saas_subscription(id));
CREATE TABLE saas_activation (id VARCHAR(36) PRIMARY KEY,license_id VARCHAR(36) NOT NULL,fingerprint_hash VARCHAR(64) NOT NULL,device_name VARCHAR(180),platform VARCHAR(80),application_version VARCHAR(80),status VARCHAR(30) NOT NULL,activated_at TIMESTAMP NOT NULL,last_heartbeat_at TIMESTAMP,deactivated_at TIMESTAMP,CONSTRAINT fk_activation_license FOREIGN KEY(license_id) REFERENCES saas_license(id),CONSTRAINT ux_activation_fingerprint UNIQUE(license_id,fingerprint_hash));
CREATE TABLE saas_usage_event (id VARCHAR(36) PRIMARY KEY,subscription_id VARCHAR(36) NOT NULL,meter VARCHAR(100) NOT NULL,quantity DECIMAL(19,4) NOT NULL,idempotency_key VARCHAR(120) NOT NULL UNIQUE,occurred_at TIMESTAMP NOT NULL,metadata_json TEXT,CONSTRAINT fk_usage_subscription FOREIGN KEY(subscription_id) REFERENCES saas_subscription(id));
CREATE TABLE saas_release (id VARCHAR(36) PRIMARY KEY,product_id VARCHAR(36) NOT NULL,version VARCHAR(80) NOT NULL,platform VARCHAR(50) NOT NULL,channel VARCHAR(40) NOT NULL,download_url VARCHAR(1000) NOT NULL,checksum VARCHAR(128),minimum_plan VARCHAR(100),active BOOLEAN NOT NULL,published_at TIMESTAMP NOT NULL,CONSTRAINT fk_release_product FOREIGN KEY(product_id) REFERENCES saas_product(id));
CREATE INDEX ix_saas_license_email ON saas_license(customer_email);CREATE INDEX ix_saas_license_order ON saas_license(order_id);CREATE INDEX ix_saas_subscription_email ON saas_subscription(customer_email);CREATE INDEX ix_saas_usage_meter ON saas_usage_event(meter,occurred_at);
